const redis = require('redis');
let redisPw = ''; try { redisPw = $env.REDIS_PASSWORD || ''; } catch(e) {}
const client = redis.createClient({ socket: { host: 'redis', port: 6379 }, password: redisPw || undefined });
await client.connect();
try {
  const items = await client.lRange('alice:dms:plaintext', 0, 49);
  if (items.length === 0) {
    return [{ json: { _empty: true } }];
  }
  await client.lTrim('alice:dms:plaintext', items.length, -1);
  await client.hIncrBy('alice:dms:run:stats', 'batches_run', 1);
  const results = [];
  for (const raw of items) {
    try {
      const parsed = JSON.parse(raw);
      results.push({ json: { ...parsed, _empty: false } });
    } catch(e) {
      results.push({ json: { _empty: false, _parse_error: true, extraction_failed: true, file_hash: null, file_path: raw.slice(0, 200), plaintext: '' } });
    }
  }
  return results;
} finally {
  await client.quit();
}

