const redis = require('redis');
const axios = require('axios');
const item = $input.first().json;
const validTypes = ['Invoice', 'BankStatement', 'Document', 'Email', 'SecuritySettlement', 'Contract'];
let docType = 'Document';
let retried = false;
let retryFailed = false;
let ollamaModel = 'qwen3:14b'; try { ollamaModel = $env.OLLAMA_MODEL_DMS || 'qwen3:14b'; } catch(e) {}

function tryParse(responseStr) {
  const parsed = JSON.parse(responseStr);
  if (validTypes.includes(parsed.document_type)) return parsed.document_type;
  return null;
}

try {
  const response = item.response || item.body?.response || '';
  const result = tryParse(response);
  if (result) { docType = result; }
  else { throw new Error('Invalid document_type in response'); }
} catch(e) {
  // Retry: re-call Ollama with same prompt
  retried = true;
  try {
    const origItem = $('IF: Auto Classify').first().json;
    const prompt = 'You are a document classifier. Analyze the following document text and determine the document type.\nChoose EXACTLY ONE of the following types: Invoice, BankStatement, Document, Email, SecuritySettlement, Contract\nRespond ONLY with a JSON object: {"document_type": "<Type>"}\n\nDocument text:\n' + (origItem.plaintext || '').slice(0, 20000);
    const retryResp = await axios.post('http://ollama-3090:11434/api/generate', { model: ollamaModel, prompt, stream: false, format: 'json', options: { temperature: 0 } }, { timeout: 30000 });
    const retryResult = tryParse(retryResp.data.response || '');
    if (retryResult) { docType = retryResult; }
    else { retryFailed = true; }
  } catch(retryErr) {
    retryFailed = true;
  }
}

let redisPw = ''; try { redisPw = $env.REDIS_PASSWORD || ''; } catch(e) {}
const client = redis.createClient({ socket: { host: 'redis', port: 6379 }, password: redisPw || undefined });
await client.connect();
try {
  await client.hIncrBy('alice:dms:run:stats', 'llm_classified', 1);
  if (retried) await client.hIncrBy('alice:dms:run:stats', 'llm_retries', 1);
  if (retryFailed) await client.hIncrBy('alice:dms:run:stats', 'llm_retry_failures', 1);
} finally {
  await client.quit();
}
const origItem = $('IF: Auto Classify').first().json;
const result = { ...origItem, _document_type: docType, _llm_classified: true };
if (retryFailed) result._llm_retry_failed = true;
return [{ json: result }];

