}

function toISODate(val) {
  if (!val) return null;
  try {
    const d = new Date(val);
    if (isNaN(d.getTime())) return null;
    return d.toISOString();
  } catch(e) { return null; }
}

function toNum(val) {
  if (val === null || val === undefined || val === '') return null;
  const n = parseFloat(val);
  return isNaN(n) ? null : n;
}

const result = { ...originalItem, _extracted: extracted, _extraction_ok: true };
if (retryFailed) result._llm_retry_failed = true;
return [{ json: result }];

const item = $input.first().json;

// className allowlist — prevents GraphQL injection via manipulated _document_type
const validClasses = ['Invoice', 'BankStatement', 'Document', 'Email', 'SecuritySettlement', 'Contract'];
const className = item._document_type;
if (!className || !validClasses.includes(className)) {
  console.warn(`[Build Weaviate Query] Invalid className: ${className} — skipping document`);
  return [{ json: { ...item, _skip: true, _skip_reason: `Invalid className: ${className}` } }];
}

// Full escape for filePath — prevents GraphQL string injection via control characters
const rawPath = item.file_path || '';
const filePath = rawPath
  .replace(/\\/g, '\\\\')
  .replace(/"/g, '\\"')
  .replace(/\n/g, '\\n')
  .replace(/\r/g, '\\r')
  .replace(/\t/g, '\\t')
  .replace(/[\x00-\x1f]/g, c => '\\u' + c.charCodeAt(0).toString(16).padStart(4, '0'));

if (!filePath) {
  console.warn('[Build Weaviate Query] Empty filePath after escaping — skipping document');
  return [{ json: { ...item, _skip: true, _skip_reason: 'Empty filePath after escaping' } }];
}

const query = `{ Get { ${className}(where: { path: ["filePath"], operator: Equal, valueText: "${filePath}" }, limit: 1) { _additional { id } } } }`;
return [{ json: { ...item, _weaviate_query: query } }];

const item = $input.first().json;
let existingId = null;
