const redis = require('redis');
const item = $input.first().json;

const insertSuccess = !item.error && (item.statusCode === 200 || item.statusCode === 201 || !item.statusCode);

let redisPw = ''; try { redisPw = $env.REDIS_PASSWORD || ''; } catch(e) {}
const client = redis.createClient({ socket: { host: 'redis', port: 6379 }, password: redisPw || undefined });
await client.connect();
try {
  if (insertSuccess) {
    if (item.file_hash) {
      await client.sRem('alice:dms:queued_files', item.file_hash);
      await client.sAdd('alice:dms:processed', item.file_hash);
      if (item.file_path) {
        const oldHash = await client.hGet('alice:dms:path_to_hash', item.file_path);
        if (oldHash && oldHash !== item.file_hash) {
          await client.hDel('alice:dms:path_to_hash', item.file_path);
          await client.sRem(`alice:dms:hash_to_paths:${oldHash}`, item.file_path);
        }
        await client.hSet('alice:dms:path_to_hash', item.file_path, item.file_hash);
        await client.sAdd(`alice:dms:hash_to_paths:${item.file_hash}`, item.file_path);
      }
    }
    await client.hIncrBy('alice:dms:run:stats', 'processed', 1);
  } else {
    await client.hIncrBy('alice:dms:run:stats', 'failed', 1);
  }
} finally {
  await client.quit();
}

return [{ json: { ...item, _weaviate_inserted: insertSuccess } }];

