  await client.del('alice:dms:run:start_time');
  await client.del('alice:dms:run:stats');
  const log = {
    event: 'alice-dms-processor-aborted',
    reason: 'weaviate_unreachable',
    processed: parseInt(stats.processed || '0'),
    failed: parseInt(stats.failed || '0'),
    skipped: parseInt(stats.skipped || '0'),
    llm_classified: parseInt(stats.llm_classified || '0'),
    used_suggested_type: parseInt(stats.used_suggested_type || '0'),
    batches_run: parseInt(stats.batches_run || '0'),
    runtime_seconds,
    remaining_queue: remainingQueue,
    timestamp: new Date().toISOString()
  };
  console.log(JSON.stringify(log));
} finally {
  await client.quit();
}
throw new Error('Weaviate insert failed — aborting run. Items remain in queued_files for retry.');
